export function useListBookingFiles<TData = Awaited<ReturnType<typeof listBookingFiles>>, TError = ErrorType<unknown>>(
 bookingId: number, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof listBookingFiles>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getListBookingFilesQueryOptions(bookingId,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return withQueryKey(query, queryOptions.queryKey);
}







export const getCreateBookingFileUrl = (bookingId: number,) => {




  return `/api/bookings/${bookingId}/files`
}

export const createBookingFile = async (bookingId: number,
    deliveryFileInput: DeliveryFileInput, options?: RequestInit): Promise<DeliveryFile> => {

  return customFetch<DeliveryFile>(getCreateBookingFileUrl(bookingId),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(deliveryFileInput)
  }
);}




export const getCreateBookingFileMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof createBookingFile>>, TError,{bookingId: number;data: BodyType<DeliveryFileInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof createBookingFile>>, TError,{bookingId: number;data: BodyType<DeliveryFileInput>}, TContext> => {

const mutationKey = ['createBookingFile'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof createBookingFile>>, {bookingId: number;data: BodyType<DeliveryFileInput>}> = (props) => {
          const {bookingId,data} = props ?? {};

          return  createBookingFile(bookingId,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type CreateBookingFileMutationResult = NonNullable<Awaited<ReturnType<typeof createBookingFile>>>
    export type CreateBookingFileMutationBody = BodyType<DeliveryFileInput>
    export type CreateBookingFileMutationError = ErrorType<unknown>

    export const useCreateBookingFile = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof createBookingFile>>, TError,{bookingId: number;data: BodyType<DeliveryFileInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof createBookingFile>>,
        TError,
        {bookingId: number;data: BodyType<DeliveryFileInput>},
        TContext
      > => {
      return useMutation(getCreateBookingFileMutationOptions(options));
    }

